// Home Page - Hero section with search
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import './Home.css';

const Home = () => {
  const navigate = useNavigate();
  const [searchData, setSearchData] = useState({
    pickupLocation: '',
    pickupDate: '',
    returnDate: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setSearchData(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSearch = (e) => {
    e.preventDefault();
    
    if (!searchData.pickupLocation) {
      toast.error('Please select a pickup location');
      return;
    }
    
    if (!searchData.pickupDate || !searchData.returnDate) {
      toast.error('Please select pickup and return dates');
      return;
    }

    // Navigate to cars page with search params
    navigate('/cars');
  };

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section className="hero-section" style={{
        minHeight: '90vh',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
        position: 'relative',
        overflow: 'hidden',
      }}>
        <div style={{
          maxWidth: '1200px',
          width: '100%',
          padding: '2rem',
          textAlign: 'center',
          zIndex: 2,
        }}>
          {/* Hero Title */}
          <h1 style={{
            fontSize: 'clamp(2.5rem, 5vw, 4rem)',
            fontWeight: 'bold',
            marginBottom: '2rem',
            color: '#1a1a1a',
            letterSpacing: '-0.02em',
          }}>
            Luxury cars on Rent
          </h1>

          {/* Search Form */}
          <form onSubmit={handleSearch} style={{
            background: 'white',
            borderRadius: '1rem',
            padding: '2rem',
            boxShadow: '0 10px 40px rgba(0,0,0,0.1)',
            maxWidth: '900px',
            margin: '0 auto 3rem auto',
          }}>
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
              gap: '1.5rem',
              alignItems: 'end',
            }}>
              {/* Pickup Location */}
              <div style={{ textAlign: 'left' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '0.5rem',
                  color: '#1a1a1a',
                  fontWeight: '600',
                  fontSize: '0.95rem',
                }}>
                  Pickup Location
                </label>
                <select
                  name="pickupLocation"
                  value={searchData.pickupLocation}
                  onChange={handleChange}
                  required
                  style={{
                    width: '100%',
                    padding: '0.875rem 1rem',
                    border: '2px solid #e0e0e0',
                    borderRadius: '0.5rem',
                    fontSize: '1rem',
                    color: searchData.pickupLocation ? '#1a1a1a' : '#999',
                    cursor: 'pointer',
                    background: 'white',
                  }}
                >
                  <option value="">Please select location</option>
                  <option value="Mumbai">Mumbai</option>
                  <option value="Delhi">Delhi</option>
                  <option value="Bangalore">Bangalore</option>
                  <option value="Pune">Pune</option>
                  <option value="Hyderabad">Hyderabad</option>
                  <option value="Chennai">Chennai</option>
                  <option value="Kolkata">Kolkata</option>
                  <option value="Ahmedabad">Ahmedabad</option>
                </select>
              </div>

              {/* Pick-up Date */}
              <div style={{ textAlign: 'left' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '0.5rem',
                  color: '#1a1a1a',
                  fontWeight: '600',
                  fontSize: '0.95rem',
                }}>
                  Pick-up Date
                </label>
                <input
                  type="date"
                  name="pickupDate"
                  value={searchData.pickupDate}
                  onChange={handleChange}
                  min={new Date().toISOString().split('T')[0]}
                  required
                  style={{
                    width: '100%',
                    padding: '0.875rem 1rem',
                    border: '2px solid #e0e0e0',
                    borderRadius: '0.5rem',
                    fontSize: '1rem',
                    cursor: 'pointer',
                  }}
                />
              </div>

              {/* Return Date */}
              <div style={{ textAlign: 'left' }}>
                <label style={{
                  display: 'block',
                  marginBottom: '0.5rem',
                  color: '#1a1a1a',
                  fontWeight: '600',
                  fontSize: '0.95rem',
                }}>
                  Return Date
                </label>
                <input
                  type="date"
                  name="returnDate"
                  value={searchData.returnDate}
                  onChange={handleChange}
                  min={searchData.pickupDate || new Date().toISOString().split('T')[0]}
                  required
                  style={{
                    width: '100%',
                    padding: '0.875rem 1rem',
                    border: '2px solid #e0e0e0',
                    borderRadius: '0.5rem',
                    fontSize: '1rem',
                    cursor: 'pointer',
                  }}
                />
              </div>

              {/* Search Button */}
              <button
                type="submit"
                style={{
                  padding: '0.875rem 2rem',
                  background: '#0066cc',
                  color: 'white',
                  border: 'none',
                  borderRadius: '0.5rem',
                  fontSize: '1rem',
                  fontWeight: 'bold',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '0.5rem',
                  transition: 'all 0.3s ease',
                }}
                onMouseOver={(e) => e.target.style.background = '#0052a3'}
                onMouseOut={(e) => e.target.style.background = '#0066cc'}
              >
                🔍 Search
              </button>
            </div>
          </form>

          {/* Hero Car Image */}
          <div style={{
            maxWidth: '1000px',
            margin: '0 auto',
            position: 'relative',
          }}>
            <img
              src="https://images.unsplash.com/photo-1605559424843-9e4c228bf1c2?w=1200&auto=format&fit=crop"
              alt="Luxury Car"
              style={{
                width: '100%',
                height: 'auto',
                objectFit: 'contain',
                filter: 'drop-shadow(0 20px 40px rgba(0,0,0,0.15))',
              }}
            />
          </div>

          {/* Quick Stats */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: '2rem',
            marginTop: '3rem',
            maxWidth: '900px',
            margin: '3rem auto 0',
          }}>
            <div style={{ textAlign: 'center' }}>
              <h3 style={{ fontSize: '2.5rem', color: '#0066cc', margin: '0 0 0.5rem 0' }}>18+</h3>
              <p style={{ color: '#6c757d', margin: 0 }}>Premium Cars</p>
            </div>
            <div style={{ textAlign: 'center' }}>
              <h3 style={{ fontSize: '2.5rem', color: '#0066cc', margin: '0 0 0.5rem 0' }}>24/7</h3>
              <p style={{ color: '#6c757d', margin: 0 }}>Customer Support</p>
            </div>
            <div style={{ textAlign: 'center' }}>
              <h3 style={{ fontSize: '2.5rem', color: '#0066cc', margin: '0 0 0.5rem 0' }}>100%</h3>
              <p style={{ color: '#6c757d', margin: 0 }}>Verified Cars</p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
